// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter: (predicate: (row: Record<string, unknown>) => boolean) => Record<string, unknown>[];
  sum: (column: string) => number;
  average: (column: string) => number;
  count: () => number;
  groupBy: (column: string) => Map<unknown, Record<string, unknown>[]>;
}

// ─── Field-level parser (handles quoting / escaping) ─────────────────────────

function parseFields(line: string, delimiter: string, quote: string): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // trailing delimiter produced an empty field
      fields.push("");
      break;
    }

    if (line[i] === quote) {
      // ── quoted field ──
      let value = "";
      i++; // skip opening quote
      while (i < len) {
        if (line[i] === quote) {
          if (i + 1 < len && line[i + 1] === quote) {
            // escaped quote
            value += quote;
            i += 2;
          } else {
            // closing quote
            i++; // skip closing quote
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }
      fields.push(value);
      // skip delimiter (or we're at end of line)
      if (i < len && line[i] === delimiter) {
        i++;
        // if delimiter is the very last char, there's one more empty field
        if (i === len) {
          fields.push("");
        }
      }
    } else {
      // ── unquoted field ──
      let end = line.indexOf(delimiter, i);
      if (end === -1) {
        fields.push(line.substring(i));
        break;
      } else {
        fields.push(line.substring(i, end));
        i = end + 1;
        // trailing delimiter → empty field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// ─── Multiline-aware line splitter ───────────────────────────────────────────
// We can't just split on the line separator because quoted fields may contain
// the line separator literally. This function yields complete "logical" lines.

function splitLogicalLines(input: string, lineSeparator: string, quote: string): string[] {
  const lines: string[] = [];
  const parts = input.split(lineSeparator);
  let current: string | null = null;

  for (const part of parts) {
    if (current !== null) {
      current += lineSeparator + part;
    } else {
      current = part;
    }

    // Count unescaped quotes. If odd we're still inside a quoted field that
    // spans multiple lines — keep accumulating.
    if (countActiveQuotes(current, quote) % 2 === 0) {
      lines.push(current);
      current = null;
    }
  }

  // Leftover (unclosed quote) — push anyway; parseFields will handle it and
  // the caller can record an error if the field count is wrong.
  if (current !== null) {
    lines.push(current);
  }

  return lines;
}

/** Count quote characters that are NOT part of an escaped pair (""). */
function countActiveQuotes(s: string, quote: string): number {
  let count = 0;
  let i = 0;
  while (i < s.length) {
    if (s[i] === quote) {
      if (i + 1 < s.length && s[i + 1] === quote) {
        // escaped pair — skip both, don't count
        i += 2;
      } else {
        count++;
        i++;
      }
    } else {
      i++;
    }
  }
  return count;
}

// ─── Type coercion ───────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // boolean
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // number – must be the *entire* string, not just a prefix
  if (/^-?\d+$/.test(value)) {
    const n = Number(value);
    if (Number.isSafeInteger(n)) return n;
  }

  if (/^-?\d+\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator ?? "\n";

  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  if (input.trim() === "") {
    return buildResult([], [], errors);
  }

  const logicalLines = splitLogicalLines(input, lineSeparator, quote);

  // Drop trailing empty line that's common with a trailing newline
  if (logicalLines.length > 0 && logicalLines[logicalLines.length - 1].trim() === "") {
    logicalLines.pop();
  }

  if (logicalLines.length === 0) {
    return buildResult([], [], errors);
  }

  // First logical line → headers (always strings, trimmed)
  const headers = parseFields(logicalLines[0], delimiter, quote).map((h) => h.trim());

  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < logicalLines.length; i++) {
    const line = logicalLines[i];

    // skip blank lines
    if (line.trim() === "") continue;

    const fields = parseFields(line, delimiter, quote);

    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1, // 1-based, header is row 1
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue;
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerce(fields[j]);
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

// ─── Build the rich result object ────────────────────────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}
